using System;
using System.Data;
using System.Data.SqlClient;
using System.Net.Http;
using Microsoft.AspNetCore.Mvc;

namespace MyApi
{
    [ApiController]
    public class UserSearchController : ControllerBase
    {
        private readonly string _connectionString;

        public UserSearchController(string connectionString)
        {
            _connectionString = connectionString;
        }

        [HttpGet("users")]
        public async Task<IActionResult> SearchUsers([FromQuery] string email)
        {
            using var connection = new SqlConnection(_connectionString);
            await connection.OpenAsync();

            // Use ADO.NET to query the database and retrieve users
            using var command = new SqlCommand("SELECT * FROM Users WHERE Email = @Email", connection);
            command.Parameters.AddWithValue("@Email", email);
            using var reader = await command.ExecuteReaderAsync();

            // Serialize the users as JSON
            var serializer = new System.Text.Json.Serialization.JsonSerializer();
            List<User> users = new List<User>();
            while (reader.Read())
            {
                users.Add(new User
                {
                    Id = reader["Id"].ToString(),
                    Email = reader["Email"].ToString()
                });
            }
            return Ok(users);
        }
    }
